#include <stdio.h>
int main() {
    int arr[5] = {10, 20, 30, 40, 50};
    printf("%d\n", arr[0]);  // 10
    printf("%d\n", arr[4]);  // 50

    int len = sizeof(arr) / sizeof(arr[0]); // 5
    for (int i = 0; i < len; i++) {
        printf("%d ", arr[i]);
    }
    // 10 20 30 40 50
    return 0;
}

int arr[] = {1, 2, 3, 4, 5};

// Array name IS the address of first element:
printf("%p\n", arr);      // memory address
printf("%p\n", &arr[0]); // SAME address!

// Pointer arithmetic:
int *p = arr;
printf("%d\n", *(p+2)); // 3  (arr[2])
printf("%d\n", p[2]);   // 3  (same!)

