examples.code:
#include <stdio.h>
#include <string.h>

char name[] = "Alice";  // auto-adds \0
printf("%s\n", name);       // Alice
printf("%lu\n", strlen(name)); // 5 (not 6, null not counted)

// String comparison — use strcmp, NOT ==:
char a[] = "hello";
char b[] = "hello";
if (strcmp(a, b) == 0) printf("equal!\n"); // equal!
// a == b compares POINTERS, not content!

#include <string.h>
char s1[20] = "Hello";
char s2[] = " World";

strlen(s1);          // 5
strcat(s1, s2);      // s1 = "Hello World"
strcpy(s1, "Reset"); // s1 = "Reset"
strcmp("abc","abc"); // 0 (equal)
strcmp("abc","abd"); // negative (a<b)
strcmp("abd","abc"); // positive (a>b)

