examples.code:
#include <stdio.h>
#include <string.h>

struct Player {
    char name[50];
    int score;
    int level;
};

int main() {
    struct Player p1;
    strcpy(p1.name, "Neo");
    p1.score = 100;
    p1.level = 5;

    printf("%s: L%d, %d pts\n",
           p1.name, p1.level, p1.score);
    return 0;
}

typedef struct {
    char name[50];
    float hp;
} Enemy;

Enemy boss = {"Dragon", 500.0f};
printf("%s %.1f\n", boss.name, boss.hp);

// Pointer to struct — use ->:
Enemy *ptr = &boss;
printf("%s\n", ptr->name);  // Dragon
ptr->hp -= 100;             // changes boss.hp!

